import React, { Fragment, useEffect, useState } from 'react'
import { Card, CardBody, CardHeader, Col, Container, Row } from 'reactstrap';
import Breadcrumb from '../components/common/Breadcrumb';
import NodeDashboard from '../components/common/NodeDashboard';
import { UserState } from '../context/User';

const Dashboard = () => {
  const { user } = UserState();
  const { nodes, setNodes } = useState();
  const [context, setContext] = useState();
  const [loading, setLoading] = useState(true);
  const fetchNode = async (para) => {
    let dataRaw = await fetch("/Data/Read", {
      method: "POST",
      headers: {
        "Content-type": "application/json;charset=utf-8",
        method: "POST",
      },
      body: JSON.stringify({
        accountId: para,
      })
    });
    let data = await dataRaw.json();
    return data;
  };
  useEffect(() => {
    setContext(<div>Loading...</div>)
    setLoading(true);
    if (user) {
      fetchNode(user._id).then((result) => {
        if (result) {
          setContext(result.Data.project.map((element) => {
            return (
              <Card key={element.projectId}>
                <CardHeader>
                  <h5>{element.name}</h5>
                </CardHeader>
                <CardBody>
                  <Row>
                    
                  </Row>
                </CardBody>
              </Card>
            );
          }));
          setLoading(false);
        }
      });
    }
  }, [user])
  return (
    <Fragment>
      {
        user && <Breadcrumb title="Dashboard" parent="Dashboard" />
      }
      <Container fluid={true}>
        {loading && <div>Loading...</div>}
        {!loading &&
          context
        }
        <Card>
          <CardHeader>
            <h5>Products Category</h5>
          </CardHeader>
          <CardBody>
            <Row>
              <NodeDashboard title={`Flowin`} unit={`m3/h`} key={`1`} />
              <NodeDashboard title={`Flowout`} unit={`m3/h`} key={`2`} />
            </Row>
          </CardBody>
        </Card>

        <Card>
          <CardHeader>
            <h5>Products Category2</h5>
          </CardHeader>
          <CardBody>
            <Row>
              <NodeDashboard title={`Cod`} unit={`m3/h`} key={`3`} />
              <NodeDashboard title={`Tss`} unit={`m3/h`} key={`4`} />
              <NodeDashboard title={`Tss`} unit={`m3/h`} key={`5`} />
              <NodeDashboard title={`Tss`} unit={`m3/h`} key={`6`} />
              <NodeDashboard title={`Tss`} unit={`m3/h`} key={`7`} />
            </Row>
          </CardBody>
        </Card>

      </Container>

    </Fragment>
  )
}

export default Dashboard;
